import numpy as np
from typing import Dict

KYBER_PARAMS = {
    'Kyber512': {'k': 2, 'pk': 800, 'sk': 1632, 'ct': 768, 'classical': 143, 'quantum': 128},
    'Kyber768': {'k': 3, 'pk': 1184, 'sk': 2400, 'ct': 1088, 'classical': 207, 'quantum': 192},
    'Kyber1024': {'k': 4, 'pk': 1568, 'sk': 3168, 'ct': 1568, 'classical': 272, 'quantum': 256}
}

CLASSICAL_SCHEMES = {
    'RSA-2048': {'pk': 256, 'ct': 256, 'classical': 112, 'quantum': 0},
    'RSA-3072': {'pk': 384, 'ct': 384, 'classical': 128, 'quantum': 0},
    'ECDH-P256': {'pk': 64, 'ct': 64, 'classical': 128, 'quantum': 0},
    'X25519': {'pk': 32, 'ct': 32, 'classical': 128, 'quantum': 0}
}

def kyber_security_analysis(variant: str) -> Dict:
    params = KYBER_PARAMS[variant]

    # Effective lattice dimension
    n = 256
    k = params['k']
    effective_dim = n * k

    # Best known attack (Core-SVP cost)
    # Classical: 2^(0.292 * dim)
    # Quantum: 2^(0.265 * dim)
    classical_cost = 0.292 * effective_dim
    quantum_cost = 0.265 * effective_dim

    return {
        'variant': variant,
        'module_rank': k,
        'effective_dimension': effective_dim,
        'public_key_bytes': params['pk'],
        'secret_key_bytes': params['sk'],
        'ciphertext_bytes': params['ct'],
        'classical_security_bits': params['classical'],
        'quantum_security_bits': params['quantum'],
        'nist_level': {2: 1, 3: 3, 4: 5}[k],
        'core_svp_classical': f'2^{classical_cost:.0f}',
        'core_svp_quantum': f'2^{quantum_cost:.0f}'
    }

def compare_to_classical() -> Dict:
    comparisons = {}

    for variant, params in KYBER_PARAMS.items():
        comparisons[variant] = {
            'pk_bytes': params['pk'],
            'ct_bytes': params['ct'],
            'quantum_secure': True,
            'quantum_bits': params['quantum']
        }

    for scheme, params in CLASSICAL_SCHEMES.items():
        comparisons[scheme] = {
            'pk_bytes': params['pk'],
            'ct_bytes': params['ct'],
            'quantum_secure': False,
            'classical_bits': params['classical']
        }

    return {
        'schemes': comparisons,
        'size_overhead_kyber768_vs_x25519': {
            'pk': KYBER_PARAMS['Kyber768']['pk'] / CLASSICAL_SCHEMES['X25519']['pk'],
            'ct': KYBER_PARAMS['Kyber768']['ct'] / CLASSICAL_SCHEMES['X25519']['ct']
        }
    }

def bandwidth_analysis(num_connections: int = 1000000) -> Dict:
    results = {}

    for variant, params in KYBER_PARAMS.items():
        # Key exchange: send pk + ct
        per_connection = params['pk'] + params['ct']
        total_bytes = per_connection * num_connections

        results[variant] = {
            'per_connection_bytes': per_connection,
            'total_GB': total_bytes / (1024**3),
            'quantum_secure': True
        }

    # Compare to X25519
    x25519_per = 64  # 32 + 32
    results['X25519'] = {
        'per_connection_bytes': x25519_per,
        'total_GB': (x25519_per * num_connections) / (1024**3),
        'quantum_secure': False
    }

    results['overhead'] = {
        'kyber768_vs_x25519': results['Kyber768']['per_connection_bytes'] / results['X25519']['per_connection_bytes']
    }

    return results
